function setGenesisPoolInfo(GenesisInfo calldata _genesisInfo, TokenAllocation calldata _allocationInfo, address _auction) external onlyManager(){
    genesisInfo = _genesisInfo;

    genesisInfo.duration = BlackTimeLibrary.epochMultiples(genesisInfo.duration);
    genesisInfo.startTime = BlackTimeLibrary.epochStart(genesisInfo.startTime);

    allocationInfo.proposedNativeAmount = _allocationInfo.proposedNativeAmount;
    allocationInfo.proposedFundingAmount = _allocationInfo.proposedFundingAmount;
    allocationInfo.allocatedNativeAmount = 0;
    allocationInfo.allocatedFundingAmount = 0;
    allocationInfo.refundableNativeAmount = 0;

    auction = IAuction(_auction);
    poolStatus = PoolStatus.NATIVE_TOKEN_DEPOSITED;
}

function getGenesisPool(address nativeToken) public view returns (address) {
    address[] memory pools = genesisPools[nativeToken];
    uint length = pools.length;

    if (length == 0) {
        return address(0);
    }
    if(IGenesisPool(pools[length - 1]).poolStatus() != IGenesisPoolBase.PoolStatus.NOT_QUALIFIED)
    {
        return pools[length - 1];
    }

    return address(0);
}

genesisPool = genesisFactory.getGenesisPool(nativeToken);
if(genesisPool == address(0))
    genesisPool = genesisFactory.createGenesisPool(_sender, nativeToken, _fundingToken);

require(genesisPool != address(0), "ZA");
IERC20(nativeToken).safeTransferFrom(_sender, genesisPool, allocationInfo.proposedNativeAmount);

address auction = auctionFactory.auctions(auctionIndex);
auction = auction == address(0) ? auctionFactory.auctions(0) : auction;
if(!isNativeToken[nativeToken]){
    nativeTokens.push(nativeToken); 
    isNativeToken[nativeToken] = true;
}
IGenesisPool(genesisPool).setGenesisPoolInfo(genesisPoolInfo, allocationInfo, auction);
